CREATE TABLE IF NOT EXISTS tenants (id integer PRIMARY KEY, first_name varchar, last_name varchar, address1 varchar, address2 varchar, city varchar, state varchar, zip varchar);

CREATE TABLE IF NOT EXISTS enrollments (id integer primary key, active bool default false, tenant_id integer, product varchar, riders varchar);

CREATE TABLE IF NOT EXISTS historical_shipments (
  id integer PRIMARY KEY,
  tenant_id integer REFERENCES tenants(id),
  recipient_name varchar NOT NULL,
  address1 varchar NOT NULL,
  address2 varchar,
  city varchar NOT NULL,
  state varchar NOT NULL,
  zip varchar NOT NULL,
  ship_date varchar NOT NULL,
  tracking_number varchar NOT NULL UNIQUE,
  source varchar NOT NULL,
  notes varchar
);


